example.code:
// Shortest path between two users up to 6 hops (6 degrees of separation)
MATCH path = shortestPath(
    (a:User {id: '123'})-[:FRIEND*..6]-(b:User {id: '456'})
)
RETURN path

// Uniqueness constraint (implies an index)
CREATE CONSTRAINT user_id_unique FOR (u:User) REQUIRE u.id IS UNIQUE;
CREATE CONSTRAINT product_id_unique FOR (p:Product) REQUIRE p.id IS UNIQUE;

// Regular index for lookup by non-unique property
CREATE INDEX user_email_index FOR (u:User) ON (u.email);

// Composite index for queries filtering on multiple properties
CREATE INDEX order_status_date FOR (o:Order) ON (o.status, o.created_date);
